import { useState, useEffect } from 'react'
import { Link } from 'react-router-dom'
import { apiFetch } from '../utils/api'

/**
 * PENJELASAN PROGRAMS PAGE:
 * Halaman lengkap untuk semua program edukasi Bodogol Farm.
 * Berisi:
 * 1. Hero section programs
 * 2. Grid semua program dengan detail lengkap (dari backend)
 * 3. Fasilitas yang tersedia
 * 4. CTA booking
 */

export default function Programs() {
  const [programs, setPrograms] = useState([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')

  useEffect(() => {
    const fetchPrograms = async () => {
      try {
        const data = await apiFetch('/api/programs')
        setPrograms(data.data || [])
      } catch (err) {
        setError('Gagal memuat program')
        console.error('Error fetching programs:', err)
      } finally {
        setLoading(false)
      }
    }

    fetchPrograms()
  }, [])

  if (loading) {
    return (
      <div className="w-full min-h-screen flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-green-600 mx-auto mb-4"></div>
          <p className="text-gray-600">Memuat program...</p>
        </div>
      </div>
    )
  }

  if (error) {
    return (
      <div className="w-full min-h-screen flex items-center justify-center">
        <div className="text-center">
          <p className="text-red-600 mb-4">{error}</p>
          <button
            onClick={() => window.location.reload()}
            className="bg-green-600 text-white px-4 py-2 rounded hover:bg-green-700"
          >
            Coba Lagi
          </button>
        </div>
      </div>
    )
  }

  return (
    <div className="w-full">

      {/* HERO SECTION PROGRAMS */}
      <section className="bg-gradient-to-r from-blue-600 to-green-600 text-white py-20">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
          <h1 className="text-5xl font-bold mb-6">
            Program Edukasi Bodogol Farm
          </h1>
          <p className="text-xl text-blue-100 max-w-3xl mx-auto">
            Berbagai program edukasi peternakan yang dirancang untuk semua kalangan,
            dari anak PAUD hingga profesional peternakan.
          </p>
        </div>
      </section>

      {/* PROGRAMS GRID */}
      <section className="py-16 bg-white">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            {programs.map((program) => (
              <div
                key={program._id}
                className="bg-white border-2 border-gray-200 rounded-lg overflow-hidden shadow-md hover:shadow-lg transition"
              >

                {/* Program Image */}
                <div className="h-64 bg-gradient-to-br from-green-400 to-green-600 flex items-center justify-center text-white text-6xl">
                  📚
                </div>

                {/* Program Details */}
                <div className="p-8">

                  {/* Header */}
                  <div className="mb-6">
                    <h3 className="text-2xl font-bold text-gray-900 mb-2">
                      {program.title}
                    </h3>
                    <p className="text-gray-600 text-sm">
                      Program Edukasi
                    </p>
                  </div>

                  {/* Description */}
                  <p className="text-gray-700 mb-6 leading-relaxed">
                    {program.description}
                  </p>

                  {/* Details */}
                  <div className="space-y-4 mb-6">

                    {/* Duration & Price */}
                    <div className="flex justify-between items-center">
                      <div>
                        <p className="text-sm text-gray-600">Durasi</p>
                        <p className="font-semibold text-gray-900">{program.duration}</p>
                      </div>
                      <div className="text-right">
                        <p className="text-sm text-gray-600">Harga</p>
                        <p className="text-2xl font-bold text-green-600">
                          Rp {program.price.toLocaleString('id-ID')}
                        </p>
                      </div>
                    </div>

                    {/* Capacity */}
                    <div>
                      <p className="text-sm text-gray-600">Kapasitas</p>
                      <p className="font-semibold text-gray-900">{program.capacity} peserta</p>
                    </div>

                    {/* Schedule */}
                    <div>
                      <p className="text-sm text-gray-600">Jadwal</p>
                      <p className="font-semibold text-gray-900">{program.schedule}</p>
                    </div>

                  </div>

                  {/* Facilities */}
                  {program.facilities && program.facilities.length > 0 && (
                    <div className="mb-6">
                      <h4 className="font-semibold text-gray-900 mb-3">Fasilitas:</h4>
                      <ul className="space-y-1">
                        {program.facilities.map((facility, index) => (
                          <li key={index} className="flex items-start text-sm text-gray-700">
                            <span className="text-green-600 mr-2">✓</span>
                            {facility}
                          </li>
                        ))}
                      </ul>
                    </div>
                  )}

                  {/* CTA Button */}
                  <Link
                    to="/booking"
                    className="w-full bg-green-600 hover:bg-green-700 text-white py-3 px-6 rounded-lg transition font-semibold text-center block"
                  >
                    Booking Sekarang
                  </Link>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* CTA SECTION */}
      <section className="py-16 bg-green-50">
        <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
          <h2 className="text-3xl font-bold text-gray-900 mb-4">
            Siap Memulai Petualangan Edukasi?
          </h2>
          <p className="text-lg text-gray-700 mb-8">
            Pilih program yang sesuai dengan kebutuhan Anda dan mulai petualangan edukasi di Bodogol Farm
          </p>
          <button className="bg-white hover:bg-gray-100 text-green-600 px-10 py-4 rounded-lg transition font-bold text-lg">
            🎯 Lihat Form Booking
          </button>
        </div>
      </section>

    </div>
  )
}

