                  <span className="text-lg font-semibold text-gray-900">Total:</span>
                  <span className="text-lg font-bold text-green-600">
                    Rp {paymentData.totalAmount.toLocaleString()}
                  </span>
                </div>
                <div className="flex justify-between">
                  <span className="text-gray-600">Status:</span>
                  <span className={`font-medium px-3 py-1 rounded-full text-sm ${
                    paymentData.paymentStatus === 'paid' ? 'bg-green-100 text-green-800' :
                    paymentData.paymentStatus === 'pending' ? 'bg-yellow-100 text-yellow-800' :
                    paymentData.paymentStatus === 'failed' ? 'bg-red-100 text-red-800' :
                    'bg-gray-100 text-gray-800'
                  }`}>
                    {paymentData.paymentStatus === 'paid' ? 'Lunas' :
                     paymentData.paymentStatus === 'pending' ? 'Menunggu' :
                     paymentData.paymentStatus === 'failed' ? 'Gagal' : 'Unknown'}
                  </span>
                </div>
              </div>
            </div>
          )}

          {/* Error Message */}
          {error && (
            <div className="px-6 py-4 bg-red-50 border-t border-red-200">
              <p className="text-red-800 text-sm">{error}</p>
            </div>
          )}

          {/* Actions */}
          <div className="px-6 py-6 bg-gray-50 border-t border-gray-200">
            <div className="flex flex-col sm:flex-row gap-4 justify-center">
              {config.actions.map((action, index) => (
                <Link
                  key={index}
                  to={action.href}
                  className={`px-6 py-3 rounded-lg font-semibold transition text-center ${
                    action.primary
                      ? 'bg-green-600 hover:bg-green-700 text-white'
                      : 'bg-white hover:bg-gray-50 text-gray-700 border border-gray-300'
                  }`}
                >
                  {action.text}
                </Link>
              ))}
            </div>
          </div>
        </div>

        {/* Additional Info */}
        <div className="mt-8 text-center">
          <p className="text-gray-600 text-sm">
            Ada pertanyaan? Hubungi kami di{' '}
            <a href="tel:0857-5961-6910" className="text-green-600 hover:text-green-700 font-medium">
              0857-5961-6910
            </a>{' '}
            atau email ke{' '}
            <a href="mailto:contact@bodogolfarm.com" className="text-green-600 hover:text-green-700 font-medium">
              contact@bodogolfarm.com
            </a>
          </p>
        </div>
      </div>
    </div>
  )
}

