const handleSubmit = async (e) => {
  e.preventDefault()

  if (!form.program || !form.customerName || !form.customerEmail || !form.customerPhone || !form.visitDate) {
    setError('Semua field wajib diisi')
    return
  }

  setSubmitStatus('loading')
  setError('')

  try {
    const payload = {
      program: form.program,
      customerName: form.customerName,
      customerEmail: form.customerEmail,
      customerPhone: form.customerPhone,
      participants: form.participants,
      visitDate: form.visitDate,
      specialRequests: form.specialRequests
    }

    const response = await apiFetch('/api/bookings', {
      method: 'POST',
      body: JSON.stringify(payload)
    })

    // After successful booking, create payment
    const paymentResponse = await apiFetch('/api/payments/create', {
      method: 'POST',
      body: JSON.stringify({ bookingId: response.data._id })
    })

    setSubmitStatus('success')
    setPaymentData(paymentResponse.data)
    setError('')
    console.log('Booking and payment created', { booking: response.data, payment: paymentResponse.data })
  } catch (err) {
    setError(err.message)
    setSubmitStatus('error')
  }
}

